/**
 * MedX multiselect forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Multi-SKU selection for bulk operations.
 */
const MULTISELECT_TOKENS = Object.freeze({
  primary: { value: "forms-multiselect-primary", scope: "forms" },
  secondary: { value: "forms-multiselect-secondary", scope: "forms" },
  muted: { value: "forms-multiselect-muted", scope: "forms" },
  accent: { value: "forms-multiselect-accent", scope: "forms" },
  surface: { value: "forms-multiselect-surface", scope: "forms" },
});

const MULTISELECT_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const MULTISELECT_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const multiselectRegistry = new Map();
const MULTISELECT_listeners = new Set();
let MULTISELECT_seq = 0;

function createMultiselectId(prefix = "medx-forms-multiselect") {
  MULTISELECT_seq += 1;
  return `${prefix}-${MULTISELECT_seq}`;
}

function registerMultiselect(config = {}) {
  const entryId = config.id ?? createMultiselectId();
  const preset = MULTISELECT_PRESETS[config.preset ?? "default"] ?? MULTISELECT_PRESETS.default;
  const token = MULTISELECT_TOKENS[config.token ?? preset.token] ?? MULTISELECT_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: MULTISELECT_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  multiselectRegistry.set(entryId, entry);
  notifyMultiselectListeners("register", entry);
  return entry;
}

function updateMultiselect(id, patch = {}) {
  const entry = multiselectRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyMultiselectListeners("update", entry);
  return entry;
}

function resolveMultiselect(id) {
  const entry = multiselectRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listMultiselectEntries(filter = {}) {
  let items = Array.from(multiselectRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onMultiselectEvent(listener) {
  MULTISELECT_listeners.add(listener);
  return () => MULTISELECT_listeners.delete(listener);
}

function notifyMultiselectListeners(type, entry) {
  for (const listener of MULTISELECT_listeners) {
    try {
      listener({ type, entry, registrySize: multiselectRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:multiselect] listener error", err.message);
    }
  }
}

function getMultiselectMetrics() {
  const items = listMultiselectEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(MULTISELECT_TOKENS).length,
    presets: Object.keys(MULTISELECT_PRESETS).length,
  };
}

async function runMedxMultiselect() {
  console.log("[medx:ui:forms:multiselect] runtime initialized");
  console.log(`[medx:ui:forms:multiselect] tokens=${Object.keys(MULTISELECT_TOKENS).length} presets=${Object.keys(MULTISELECT_PRESETS).length}`);

  const events = [];
  onMultiselectEvent((e) => events.push(e.type));

  const domains = Object.keys(MULTISELECT_SUPPLY_CHAIN);
  const presets = Object.keys(MULTISELECT_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerMultiselect({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/multiselect" },
    });
  }

  const first = listMultiselectEntries()[0];
  if (first) updateMultiselect(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getMultiselectMetrics();
  const resolved = first ? resolveMultiselect(first.id) : null;

  console.log(`[medx:ui:forms:multiselect] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:multiselect] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:multiselect] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:multiselect] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:multiselect] bootstrap complete");
}

module.exports = runMedxMultiselect;
